    body: request.body,
    query: request.query,
    headers: request.headers
  }
}

import type { FastifyInstance } from "fastify";
import fs from "fs";
import path from "path";
import { isAcceptableFile } from ".";
import { autoload } from "./autoload";
import { transformPathToUrl } from "./transformPathToUrl";

export async function scanFolders(
  fastify: FastifyInstance,
  baseDir: string,
  current: string,
  prefix: string
): Promise<void> {
  const combined: string = path.join(baseDir, current);
  const combinedStat: fs.Stats = fs.statSync(combined);

  if (combinedStat.isDirectory()) {
    if (!path.basename(current).startsWith("_")) {
      for (const entry of fs.readdirSync(combined)) {
        await scanFolders(fastify, baseDir, path.join(current, entry), prefix);
      }
    }
  } else if (isAcceptableFile(combined, combinedStat)) {
    await autoload(fastify, combined, transformPathToUrl(current), prefix);
  }
}

import { FastifyPluginAsyncTypebox } from "@fastify/type-provider-typebox";
import { FastifyInstance, FastifyReply, FastifyRequest } from "fastify";
import { publicSchema, secureSchema } from "./index.schema";

const indexRoutes: FastifyPluginAsyncTypebox = async (
  fastify: FastifyInstance,
): Promise<void> => {
  fastify.get(
    '/',
    {
      schema: publicSchema
    },
    async function (request: FastifyRequest, reply: FastifyReply) {
      return {
        message: 'This is a simple example of item returned by your APIs'
      };
    }
  );

  fastify.get(
    '/secure',
    {
      preHandler: [fastify.checkToken],
      schema: secureSchema
    },
    async function (request: FastifyRequest, reply: FastifyReply) {
      return {
        message:
          'Access to protected resource granted! This protected resource is displayed when the token is successfully provided.'
      };
    }
  );
};

export default indexRoutes;
